{
  "id": "xananode.canonical:schema/property-geo_coordinates",
  "title": "Geographic coordinates",
  "type": "schema",
  "subtype": "property_registry_entry",
  "importance": 4,
  "summary": "WGS84 latitude and longitude coordinates for a place or geographically located entity.",
  "registry_type": "geo_coordinates",
  "category": "space",
  "aliases": [
    "coordinates",
    "lat_lon",
    "location"
  ],
  "applies_to": [
    "place",
    "event",
    "organization",
    "source",
    "media"
  ],
  "unit_system": "WGS84",
  "value_schema": {
    "type": "object",
    "additionalProperties": false,
    "required": [
      "latitude",
      "longitude"
    ],
    "properties": {
      "latitude": {
        "type": "number",
        "minimum": -90,
        "maximum": 90
      },
      "longitude": {
        "type": "number",
        "minimum": -180,
        "maximum": 180
      },
      "altitude_m": {
        "type": "number"
      },
      "crs": {
        "type": "string",
        "const": "WGS84"
      }
    }
  },
  "examples": [
    {
      "latitude": 37.33182,
      "longitude": -122.03118,
      "crs": "WGS84"
    }
  ],
  "relationships": []
}
